import * as React from "react"
import { Link } from "gatsby"
import Layout from "../components/layout"
import Post from "../components/post"
import Img from "gatsby-image"

const ExcerptsPage = ( {data} ) => {

    console.log(data);

	return (
		<Layout>
    	 <ul className="breadcrumb">
        <li><Link to="/">Home</Link></li>
        <li>Excerpts</li>
        </ul>
        <div id="excerpts">
		{data.allMarkdownRemark.edges.map( (p) => <Excerpt key={p.id} data={p} />)}
		</div>
		</Layout>
	);
}


const Excerpt = ({ data }) => (
<div title={data.node.title}>
    <Link to={data.node.fields.slug}>
        <Img fluid={data.node.frontmatter.icon.childImageSharp.fluid} alt={data.node.frontmatter.title}  title={data.node.frontmatter.title} />
    </Link>
</div>
);


export const excerptsQuery = graphql`
query ExcerptQuery {
  allMarkdownRemark(filter: {fields: {slug: {glob: "*/excerpts/*"}}}, sort: {order: DESC, fields: frontmatter___date}) {
    edges {
      node {
        fields {
          slug
        }
        id
        frontmatter {
          date(formatString: "Y-MM-DD")
          title
          icon {
            childImageSharp {
                fluid {
                    ...GatsbyImageSharpFluid
                }
            }
          }
        }
      }
    }
  }
}`

export default ExcerptsPage
